module top_module(
    input        clk,
    input        clr,
    input  [3:0] A,
    input  [3:0] B,
    input        sub,
    output [3:0] Y
);reg [3:0] sum_diff;

    always @(posedge clk)
        if (clr) sum_diff <= 4'b0;
        else if (sub) sum_diff <= A - B;
        else sum_diff <= A + B;

    assign Y = sum_diff;

endmodule
